chapters.body:
以下の5本は、n8nの「Import from JSON」機能を使ってそのままインポートできる状態で記述しています。

**インポート方法:**
n8nの画面左上「+」→「Import from JSON」→下記JSONをペーストしてインポートします。

---

## テンプレート1: Gmail → Slack 自動転送・要約ワークフロー

**概要:** Gmailに届いた新着メールをClaude AIで100文字に要約し、Slackの指定チャンネルに転送します。重要メールの見落とし防止と、メールボックスを開く回数を削減できます。

**カスタマイズポイント:**
- `FROM_EMAIL_FILTER`: 転送対象の送信者ドメイン（例: `@client-domain.com`）を指定します。空欄にすると全メール対象になります。
- `SLACK_CHANNEL_ID`: 転送先のSlackチャンネルIDを入力します。
- `CLAUDE_SUMMARIZE_PROMPT`: 要約の指示を変更できます（例: 「件名・送信者・要約を3点で」など）。

```json
{
  "name": "Gmail → Slack 自動転送・要約",
  "nodes": [
    {
      "parameters": {
        "pollTimes": { "item": [{ "mode": "everyMinute" }] },
        "filters": { "readStatus": "unread" },
        "options": {}
      },
      "name": "Gmail Trigger",
      "type": "n8n-nodes-base.gmailTrigger",
      "typeVersion": 1,
      "position": [250, 300]
    },
    {
      "parameters": {
        "model": "claude-3-5-sonnet-20241022",
        "messages": {
          "values": [{
            "content": "以下のメールを日本語で3点の箇条書きに要約してください。\n件名: {{$json.subject}}\n本文: {{$json.text}}"
          }]
        }
      },
      "name": "Claude 要約",
      "type": "@n8n/n8n-nodes-langchain.lmChatAnthropic",
      "typeVersion": 1,
      "position": [500, 300]
    },
    {
      "parameters": {
        "channel": "[SLACK_CHANNEL_ID]",
        "text": "*新着メール通知*\n*送信者:* {{$node['Gmail Trigger'].json.from}}\n*件名:* {{$node['Gmail Trigger'].json.subject}}\n\n*要約:*\n{{$json.message.content[0].text}}"
      },
      "name": "Slack 送信",
      "type": "n8n-nodes-base.slack",
      "typeVersion": 2,
      "position": [750, 300]
    }
  ],
  "connections": {
    "Gmail Trigger": { "main": [[{ "node": "Claude 要約", "type": "main", "index": 0 }]] },
    "Claude 要約": { "main": [[{ "node": "Slack 送信", "type": "main", "index": 0 }]] }
  }
}
```

---

## テンプレート2: 週次レポート自動生成・送信ワークフロー

**概要:** 毎週月曜朝8時に、Google スプレッドシートから先週分のデータを読み取り、Claude AIでレポートに整形してGmailで送信します。週次報告メールの作成を完全に自動化できます。

**カスタマイズポイント:**
- `SPREADSHEET_ID`: レポート対象のスプレッドシートIDを入力します。
- `SHEET_NAME`: データが入っているシート名（例: `週次データ`）を指定します。
- `REPORT_RECIPIENT`: レポートの送信先メールアドレスを入力します。
- `REPORT_TEMPLATE`: レポートの書式指示をプロンプト内で変更できます。

```json
{
  "name": "週次レポート自動生成・送信",
  "nodes": [
    {
      "parameters": {
        "rule": { "interval": [{ "field": "cronExpression", "expression": "0 8 * * 1" }] }
      },
      "name": "毎週月曜 8時 トリガー",
      "type": "n8n-nodes-base.scheduleTrigger",
      "typeVersion": 1,
      "position": [250, 300]
    },
    {
      "parameters": {
        "documentId": "[SPREADSHEET_ID]",
        "sheetName": "[SHEET_NAME]",
        "options": { "headerRow": true }
      },
      "name": "スプレッドシート読取",
      "type": "n8n-nodes-base.googleSheets",
      "typeVersion": 4,
      "position": [500, 300]
    },
    {
      "parameters": {
        "model": "claude-3-5-sonnet-20241022",
        "messages": {
          "values": [{
            "content": "以下のデータをもとに、週次レポートを作成してください。\n形式: サマリー（3行）→ 主要指標→ 来週の改善提案（2点）\n\nデータ: {{JSON.stringify($json)}}"
          }]
        }
      },
      "name": "Claude レポート生成",
      "type": "@n8n/n8n-nodes-langchain.lmChatAnthropic",
      "typeVersion": 1,
      "position": [750, 300]
    },
    {
      "parameters": {
        "sendTo": "[REPORT_RECIPIENT]",
        "subject": "週次レポート - {{$now.format('YYYY年MM月DD日')}}",
        "message": "{{$json.message.content[0].text}}"
      },
      "name": "Gmail 送信",
      "type": "n8n-nodes-base.gmail",
      "typeVersion": 2,
      "position": [1000, 300]
    }
  ],
  "connections": {
    "毎週月曜 8時 トリガー": { "main": [[{ "node": "スプレッドシート読取", "type": "main", "index": 0 }]] },
    "スプレッドシート読取": { "main": [[{ "node": "Claude レポート生成", "type": "main", "index": 0 }]] },
    "Claude レポート生成": { "main": [[{ "node": "Gmail 送信", "type": "main", "index": 0 }]] }
  }
}
```

