## テンプレート3: 新規リード情報 → スプレッドシート自動記録ワークフロー

**概要:** Webhookで受け取った新規リード情報（問い合わせフォームのデータなど）を自動でGoogle スプレッドシートに記録し、Slackに通知します。リード管理の手入力を完全になくせます。

**カスタマイズポイント:**
- `SPREADSHEET_ID` と `SHEET_NAME`: 記録先のスプレッドシートを指定します。
- Webhookのパスはn8nのクレデンシャル設定後に自動生成されます。
- お使いのフォームツール（Typeform・Googleフォーム等）のWebhook送信先にn8nのWebhook URLを設定してください。

```json
{
  "name": "新規リード → スプレッドシート自動記録",
  "nodes": [
    {
      "parameters": { "httpMethod": "POST", "path": "lead-capture", "options": {} },
      "name": "Webhook 受信",
      "type": "n8n-nodes-base.webhook",
      "typeVersion": 1,
      "position": [250, 300]
    },
    {
      "parameters": {
        "documentId": "[SPREADSHEET_ID]",
        "sheetName": "[SHEET_NAME]",
        "columns": {
          "mappingMode": "defineBelow",
          "value": {
            "受付日時": "={{$now.format('YYYY-MM-DD HH:mm')}}",
            "氏名": "={{$json.body.name}}",
            "メール": "={{$json.body.email}}",
            "問い合わせ内容": "={{$json.body.message}}",
            "ステータス": "=未対応"
          }
        }
      },
      "name": "スプレッドシート記録",
      "type": "n8n-nodes-base.googleSheets",
      "typeVersion": 4,
      "position": [500, 300]
    },
    {
      "parameters": {
        "channel": "[SLACK_CHANNEL_ID]",
        "text": "*新規リードが届きました*\n*氏名:* {{$node['Webhook 受信'].json.body.name}}\n*メール:* {{$node['Webhook 受信'].json.body.email}}\n*内容:* {{$node['Webhook 受信'].json.body.message}}"
      },
      "name": "Slack 通知",
      "type": "n8n-nodes-base.slack",
      "typeVersion": 2,
      "position": [750, 300]
    }
  ],
  "connections": {
    "Webhook 受信": { "main": [[{ "node": "スプレッドシート記録", "type": "main", "index": 0 }]] },
    "スプレッドシート記録": { "main": [[{ "node": "Slack 通知", "type": "main", "index": 0 }]] }
  }
}
```

