## テンプレート4: RSSフィード → 要約 → Notion保存ワークフロー

**概要:** 指定したRSSフィードの新着記事を毎時取得し、Claude AIで日本語要約してNotionデータベースに保存します。業界ニュースのリサーチ業務を自動化できます。

**カスタマイズポイント:**
- `RSS_URL`: 監視したいRSSフィードのURL（複数設定する場合は複数のRSSノードを追加）。
- `NOTION_DATABASE_ID`: 保存先のNotionデータベースIDを入力します。
- 要約の言語・長さはプロンプト内で変更できます。

```json
{
  "name": "RSSフィード → 要約 → Notion保存",
  "nodes": [
    {
      "parameters": { "rule": { "interval": [{ "field": "hours", "hoursInterval": 1 }] } },
      "name": "毎時トリガー",
      "type": "n8n-nodes-base.scheduleTrigger",
      "typeVersion": 1,
      "position": [250, 300]
    },
    {
      "parameters": { "url": "[RSS_URL]" },
      "name": "RSS フィード取得",
      "type": "n8n-nodes-base.rssFeedRead",
      "typeVersion": 1,
      "position": [500, 300]
    },
    {
      "parameters": {
        "model": "claude-3-5-sonnet-20241022",
        "messages": {
          "values": [{
            "content": "以下の記事を日本語で150文字以内に要約してください。ポイントは3点以内でまとめてください。\n\nタイトル: {{$json.title}}\n本文抜粋: {{$json.contentSnippet}}"
          }]
        }
      },
      "name": "Claude 要約",
      "type": "@n8n/n8n-nodes-langchain.lmChatAnthropic",
      "typeVersion": 1,
      "position": [750, 300]
    },
    {
      "parameters": {
        "resource": "databasePage",
        "operation": "create",
        "databaseId": "[NOTION_DATABASE_ID]",
        "title": "={{$node['RSS フィード取得'].json.title}}",
        "propertiesUi": {
          "propertyValues": [
            { "key": "URL", "urlValue": "={{$node['RSS フィード取得'].json.link}}" },
            { "key": "要約", "textValue": "={{$json.message.content[0].text}}" },
            { "key": "取得日時", "dateValue": "={{$now}}" }
          ]
        }
      },
      "name": "Notion 保存",
      "type": "n8n-nodes-base.notion",
      "typeVersion": 2,
      "position": [1000, 300]
    }
  ],
  "connections": {
    "毎時トリガー": { "main": [[{ "node": "RSS フィード取得", "type": "main", "index": 0 }]] },
    "RSS フィード取得": { "main": [[{ "node": "Claude 要約", "type": "main", "index": 0 }]] },
    "Claude 要約": { "main": [[{ "node": "Notion 保存", "type": "main", "index": 0 }]] }
  }
}
```

