## テンプレート5: X投稿スケジュール管理ワークフロー

**概要:** Google スプレッドシートに書き込んだ投稿予定テキストを、指定時刻にX（旧Twitter）へ自動投稿します。スプレッドシートを投稿カレンダーとして使えます。

**カスタマイズポイント:**
- `SPREADSHEET_ID`: 投稿管理スプレッドシートのIDを入力します。スプレッドシートには「投稿日時」「本文」「ステータス」の3列を作成してください。
- `X_BEARER_TOKEN` と `X_API_KEY` 等: X APIのクレデンシャルをn8nのCredentials画面で設定します。
- 実行頻度（現在は15分ごと）は用途に合わせて変更できます。

```json
{
  "name": "X投稿スケジュール管理",
  "nodes": [
    {
      "parameters": { "rule": { "interval": [{ "field": "minutes", "minutesInterval": 15 }] } },
      "name": "15分ごとトリガー",
      "type": "n8n-nodes-base.scheduleTrigger",
      "typeVersion": 1,
      "position": [250, 300]
    },
    {
      "parameters": {
        "documentId": "[SPREADSHEET_ID]",
        "sheetName": "投稿カレンダー",
        "options": { "headerRow": true }
      },
      "name": "投稿リスト取得",
      "type": "n8n-nodes-base.googleSheets",
      "typeVersion": 4,
      "position": [500, 300]
    },
    {
      "parameters": {
        "conditions": {
          "options": { "version": 2 },
          "conditions": [
            { "id": "1", "leftValue": "={{$json['ステータス']}}", "rightValue": "未投稿", "operator": { "type": "string", "operation": "equals" } },
            { "id": "2", "leftValue": "={{$json['投稿日時']}}", "rightValue": "={{$now.format('YYYY-MM-DD HH:mm')}}", "operator": { "type": "string", "operation": "equals" } }
          ],
          "combinator": "and"
        }
      },
      "name": "投稿時刻チェック",
      "type": "n8n-nodes-base.filter",
      "typeVersion": 2,
      "position": [750, 300]
    },
    {
      "parameters": {
        "text": "={{$json['本文']}}",
        "additionalFields": {}
      },
      "name": "X 投稿",
      "type": "n8n-nodes-base.twitter",
      "typeVersion": 2,
      "position": [1000, 300]
    }
  ],
  "connections": {
    "15分ごとトリガー": { "main": [[{ "node": "投稿リスト取得", "type": "main", "index": 0 }]] },
    "投稿リスト取得": { "main": [[{ "node": "投稿時刻チェック", "type": "main", "index": 0 }]] },
    "投稿時刻チェック": { "main": [[{ "node": "X 投稿", "type": "main", "index": 0 }]] }
  }
}
```
